fn main() {
    let nums = vec![1, 2, 3, 4, 5, 15];

    for n in nums {
        if n % 15 == 0 {
            println!("FizzBuzz");
        } else if n % 3 == 0 {
            println!("Fizz");
        } else if n % 5 == 0 {
            println!("Buzz");
